// ============================================================
// UNIFIED PAYLOAD PARSER
// ============================================================
// Handles payloads from BOTH Supabase Database Webhooks:
//   - orders table (INSERT / UPDATE)
//   - returns table (INSERT / UPDATE)
// Detects which table the webhook came from and normalises
// everything into a single { source, event, ... } shape.
// ============================================================

const body = $input.first().json.body || $input.first().json;
let out = {};

// ---- Supabase Database Webhook format -----------------------
if (body.type === 'INSERT' || body.type === 'UPDATE') {
  const rec = body.record || {};
  const old = body.old_record || {};
  const table = (body.table || '').toLowerCase();

  // ------- ORDERS TABLE -----------
  if (table === 'orders' || rec.order_no) {
    let event = 'ORDER_UPDATED';
    if (body.type === 'INSERT') event = 'ORDER_CREATED';
    else if (old.status !== rec.status) event = 'ORDER_STATUS_CHANGED';
    else if (old.courier_tracking_number !== rec.courier_tracking_number && rec.courier_tracking_number) event = 'TRACKING_NUMBER_ADDED';
    else if (old.payment_state !== rec.payment_state) event = 'PAYMENT_STATE_CHANGED';

    // Skip irrelevant order updates (no meaningful change)
    if (event === 'ORDER_UPDATED') return [];

    let phone = (rec.customer_phone || '').replace(/^\+/, '');
    if (phone.startsWith('0')) phone = '60' + phone.substring(1);
    if (!phone.startsWith('6')) phone = '60' + phone;
    if (!phone || phone.length < 10) return [];

    out = {
      source: 'order',
      event,
      order: {
        id: rec.id,
        order_no: rec.order_no,
        status: rec.status,
        previous_status: old.status || null,
        payment_state: rec.payment_state,
        previous_payment_state: old.payment_state || null,
        total: rec.total,
        delivery_method: rec.delivery_method,
        created_at: rec.created_at,
        updated_at: rec.updated_at
      },
      customer: { name: rec.customer_name, phone, email: rec.customer_email },
      courier: {
        provider: rec.courier_provider,
        tracking_number: rec.courier_tracking_number,
        shipment_id: rec.courier_shipment_id
      }
    };
  }
  // ------- RETURNS TABLE ----------
  else if (table === 'returns' || rec.return_no) {
    let event = 'RETURN_UPDATED';
    if (body.type === 'INSERT') event = 'RETURN_CREATED';
    else if (old.status !== rec.status) event = 'RETURN_STATUS_CHANGED';

    if (event === 'RETURN_UPDATED') return [];

    out = {
      source: 'return',
      event,
      return_data: {
        id: rec.id,
        return_no: rec.return_no,
        order_id: rec.order_id,
        customer_id: rec.customer_id,
        status: rec.status,
        previous_status: old.status || null,
        reason: rec.reason,
        reason_details: rec.reason_details,
        refund_method: rec.refund_method,
        refund_amount: rec.refund_amount,
        return_shipping_free: rec.return_shipping_free,
        return_tracking_number: rec.return_tracking_number,
        return_courier: rec.return_courier,
        admin_notes: rec.admin_notes,
        rejection_reason: rec.rejection_reason,
        created_at: rec.created_at,
        updated_at: rec.updated_at
      },
      customer: { id: rec.customer_id }
    };
  }
  else {
    return []; // Unknown table
  }
}
// ---- Already-normalised payload (from webhook_logs, etc.) ----
else if (body.event) {
  out = body;
  if (body.event.startsWith('ORDER') || body.event === 'TRACKING_NUMBER_ADDED' || body.event === 'PAYMENT_STATE_CHANGED') {
    out.source = 'order';
    // Normalise phone
    let phone = (out.customer?.phone || '').replace(/^\+/, '');
    if (phone.startsWith('0')) phone = '60' + phone.substring(1);
    if (!phone.startsWith('6')) phone = '60' + phone;
    if (!phone || phone.length < 10) return [];
    out.customer.phone = phone;
  } else if (body.event.startsWith('RETURN')) {
    out.source = 'return';
  } else {
    return [];
  }
}
else {
  return []; // Unrecognised payload
}

return { json: out };

// ORDER CREATED
const data = $input.first().json;
const o = data.order;
const c = data.customer;
const site = $('Config').first().json.WEBSITE_URL;

const payLine = o.payment_state === 'UNPAID'
  ? `⏳ *Payment Status:* Pending
Please complete your payment to process your order.

💳 *Pay now:* ${site}/my-orders`
  : '✅ *Payment:* Received';

const msg = `🎉 *Order Confirmed!*

Hi ${c.name}! Thank you for your order with *AutoLab*!

📋 *Order No:* ${o.order_no}
💰 *Total:* RM ${parseFloat(o.total).toFixed(2)}
📦 *Delivery:* ${o.delivery_method === 'DELIVERY' ? 'Home Delivery' : 'Self Pickup'}

${payLine}

We'll notify you when your order is being prepared! 🚀

_Questions? Contact us:_
📞 03-4297 7668
💬 wa.me/60342977668`;

return { json: { phone: c.phone, message: msg } };

// ORDER STATUS CHANGED
const data = $input.first().json;
const o = data.order;
const c = data.customer;
const courier = data.courier;
const site = $('Config').first().json.WEBSITE_URL;

const map = {
  'PENDING_VERIFICATION': { e:'🔍', t:'Payment Under Review', b:'We've received your payment proof and it's being verified.
This usually takes 1-2 business hours during working days.' },
  'VERIFIED': { e:'✅', t:'Payment Verified!', b:'Your payment has been verified successfully!
Your order is now being processed.' },
  'PACKING': { e:'📦', t:'Order Being Packed', b:'Great news! Your order is now being packed by our warehouse team.
We'll share the tracking number once it's shipped!' },
  'DISPATCHED': { e:'🚚', t:'Order Shipped!', b:'Your order has been dispatched!' + (courier.tracking_number ? `

📬 *Tracking No:* ${courier.tracking_number}
🔗 Track: https://www.jtexpress.my/tracking?billcode=${courier.tracking_number}` : '
Tracking number will be shared shortly.') },
  'DELIVERED': { e:'🏠', t:'Order Delivered!', b:`Your order has been delivered successfully! 🎉
We hope you're happy with your purchase!

⭐ *Rate your experience:*
${site}/my-orders

📋 *Return Policy:* Within 7 days for defective or wrong items.` },
  'COMPLETED': { e:'✅', t:'Order Completed', b:'Your order has been marked as completed.
Thank you for shopping with AutoLab!

🏆 You've earned loyalty points for this purchase!' },
  'CANCELLED': { e:'❌', t:'Order Cancelled', b:'Your order has been cancelled.' + (o.payment_state === 'APPROVED' ? '

💰 A refund will be processed within 3-5 business days.' : '

If you didn't request this cancellation, please contact us immediately.') },
  'REJECTED': { e:'⚠️', t:'Order Rejected', b:'Unfortunately, your order could not be processed.

Please contact our team for more information.' }
};

const tpl = map[o.status];
if (!tpl) return [];

const msg = `${tpl.e} *${tpl.t}*

Hi ${c.name}!

${tpl.b}

📋 *Order No:* ${o.order_no}
💰 *Total:* RM ${parseFloat(o.total).toFixed(2)}

_Questions? Contact us:_
📞 03-4297 7668
💬 wa.me/60342977668`;

return { json: { phone: c.phone, message: msg } };

// TRACKING NUMBER ADDED
const data = $input.first().json;
const o = data.order;
const c = data.customer;
const courier = data.courier;

const names = { 'JNT':'J&T Express', 'LALAMOVE':'Lalamove', 'OWN_DELIVERY':'AutoLab Delivery' };
const links = { 'JNT':`https://www.jtexpress.my/tracking?billcode=${courier.tracking_number}`, 'LALAMOVE':'Check your Lalamove app for live tracking', 'OWN_DELIVERY':'Our rider will contact you directly' };

const provName = names[courier.provider] || courier.provider || 'Courier';
const trackLink = links[courier.provider] || '';

const msg = `📬 *Tracking Number Available!*\n\nHi ${c.name}!\n\nYour order *${o.order_no}* tracking details:\n\n🚛 *Courier:* ${provName}\n📦 *Tracking No:* ${courier.tracking_number}\n${trackLink ? '🔗 *Track:* ' + trackLink : ''}\n\nEstimated delivery: 2-4 business days (Peninsular MY)\n\n_Questions about your delivery?_\n📞 03-4297 7668\n💬 wa.me/60342977668`;

return { json: { phone: c.phone, message: msg } };

// PAYMENT STATE CHANGED
const data = $input.first().json;
const o = data.order;
const c = data.customer;
const site = $('Config').first().json.WEBSITE_URL;

const map = {
  'SUBMITTED': { e:'📸', t:'Payment Proof Received', b:'We've received your payment proof and will verify it shortly.
Verification usually takes 1-2 business hours during working days.' },
  'APPROVED': { e:'✅', t:'Payment Approved!', b:'Your payment has been verified and approved!
Your order is now being processed.' },
  'REJECTED': { e:'❌', t:'Payment Rejected', b:`Unfortunately, we could not verify your payment.
This could be due to unclear proof or mismatched amount.

📸 Please re-submit your payment proof at:
${site}/my-orders

Or contact us for assistance.` }
};

const tpl = map[o.payment_state];
if (!tpl) return [];

const msg = `${tpl.e} *${tpl.t}*

Hi ${c.name}!

${tpl.b}

📋 *Order No:* ${o.order_no}
💰 *Amount:* RM ${parseFloat(o.total).toFixed(2)}

_Questions? Contact us:_
📞 03-4297 7668
💬 wa.me/60342977668`;

return { json: { phone: c.phone, message: msg } };

// FORMAT RETURN NOTIFICATION MESSAGE
const retPayload = $('Parse Payload').first().json;
const ret = retPayload.return_data;
const custRaw = $input.first().json;
const cust = Array.isArray(custRaw) ? custRaw[0] : custRaw;
const site = $('Config').first().json.WEBSITE_URL;

// Normalise phone
let phone = (cust.customer_phone || '').replace(/^\+/, '');
if (phone.startsWith('0')) phone = '60' + phone.substring(1);
if (!phone.startsWith('6')) phone = '60' + phone;
if (!phone || phone.length < 10) return [];

const name = cust.customer_name || 'Customer';
const orderNo = cust.order_no || '';

const reasonLabel = ret.reason === 'DEFECTIVE' ? 'Defective/Damaged' : 'Wrong Item Received';
const methodLabel = ret.refund_method === 'EXCHANGE' ? 'Item Exchange' : 'Refund to Original Payment';

const map = {
  'PENDING': {
    e:'📋', t:'Return Request Received',
    b:'We\'ve received your return request and will review it within 1-2 business days.'
  },
  'APPROVED': {
    e:'✅', t:'Return Request Approved!',
    b:`Your return request has been approved! Please ship the item back to us.\n\n📦 *Return Instructions:*\n1. Pack the item securely in original packaging\n2. Include the RMA number on the package\n3. Ship to:\n   *AUTO LABS SDN BHD*\n   17, Jalan 7/95B, Cheras Utama\n   56100 Kuala Lumpur\n${ret.return_shipping_free ? '\n🆓 *Free return shipping* (defective item)' : '\n💰 Return shipping is at your expense'}\n\n📮 After shipping, update your tracking number at:\n${site}/my-returns`
  },
  'REJECTED': {
    e:'❌', t:'Return Request Declined',
    b:'Unfortunately, your return request has been declined.' + (ret.rejection_reason ? `\n\n📝 *Reason:* ${ret.rejection_reason}` : '')
  },
  'ITEM_SHIPPED': {
    e:'📮', t:'Return Shipment Noted',
    b:'We\'ve noted that you\'ve shipped the item back. We\'ll notify you once it arrives at our warehouse.'
  },
  'ITEM_RECEIVED': {
    e:'📬', t:'Return Item Received',
    b:'We\'ve received your returned item! It\'s now being inspected by our quality team.\nWe\'ll update you on the next steps within 1-2 business days.'
  },
  'INSPECTING': {
    e:'🔍', t:'Item Under Inspection',
    b:'Your returned item is currently being inspected.\nWe\'ll process your refund/exchange once inspection is complete.'
  },
  'REFUND_PROCESSING': {
    e:'💰', t:'Refund Being Processed',
    b:`Your refund of *RM ${ret.refund_amount ? parseFloat(ret.refund_amount).toFixed(2) : '0.00'}* is being processed.\nRefunds typically take 3-5 business days to appear in your account.`
  },
  'EXCHANGE_PROCESSING': {
    e:'🔄', t:'Exchange Being Processed',
    b:'Your exchange item is being prepared!\nWe\'ll send you the tracking number once it\'s shipped.'
  },
  'COMPLETED': {
    e:'✅', t:'Return Completed',
    b: ret.refund_method === 'EXCHANGE'
      ? 'Your exchange has been completed! The replacement item is on its way.'
      : `Your refund of *RM ${ret.refund_amount ? parseFloat(ret.refund_amount).toFixed(2) : '0.00'}* has been processed successfully.\n\nThank you for your patience! We hope to serve you better next time. 🙏`
  },
  'CANCELLED': {
    e:'🚫', t:'Return Cancelled',
    b:'Your return request has been cancelled.'
  }
};

const tpl = map[ret.status];
if (!tpl) return [];

const msg = `${tpl.e} *${tpl.t}*\n\nHi ${name}!\n\n${tpl.b}\n\n📋 *RMA No:* ${ret.return_no}\n📦 *Order:* ${orderNo}\n📝 *Reason:* ${reasonLabel}\n🔁 *Method:* ${methodLabel}\n\n_Questions about your return?_\n📞 03-4297 7668\n💬 wa.me/60342977668`;

return { json: { phone, message: msg } };

// PAYMENT REMINDER FORMATTER
// Splits unpaid orders into individual items with tiered messages
const orders = $input.first().json;
const site = $('Config (Cron)').first().json.WEBSITE_URL;

if (!Array.isArray(orders) || orders.length === 0) return [];

return orders.map(order => {
  let phone = (order.customer_phone || '').replace(/^\+/, '');
  if (phone.startsWith('0')) phone = '60' + phone.substring(1);
  if (!phone.startsWith('6')) phone = '60' + phone;
  if (!phone || phone.length < 10) return null;

  const h = order.hours_since_order || 0;
  let msg;

  if (h < 24) {
    // GENTLE (< 24h)
    msg = `👋 Hi ${order.customer_name}!

Just a friendly reminder about your AutoLab order:

📋 *Order:* ${order.order_no}
💰 *Amount:* RM ${parseFloat(order.total).toFixed(2)}

⏳ Payment is still pending. Complete your payment to start processing your order!

💳 *Pay now:* ${site}/my-orders

_Questions? We're here to help!_
📞 03-4297 7668`;
  } else if (h >= 48) {
    // URGENT (48-72h)
    msg = `⚠️ *Payment Reminder - Action Required*

Hi ${order.customer_name},

Your order *${order.order_no}* has been pending payment for over 48 hours.

📋 *Order:* ${order.order_no}
💰 *Amount:* RM ${parseFloat(order.total).toFixed(2)}

⏰ *Orders unpaid for 72+ hours will be automatically cancelled.*

Please complete your payment soon:
💳 ${site}/my-orders

If you're facing any issues, let us know:
📞 03-4297 7668
💬 wa.me/60342977668`;
  } else {
    // NUDGE (24-48h)
    msg = `💬 Hi ${order.customer_name}!

Your AutoLab order is waiting for payment:

📋 *Order:* ${order.order_no}
💰 *Amount:* RM ${parseFloat(order.total).toFixed(2)}

We're holding your items, but they may go out of stock soon! 🏃

💳 *Complete payment:* ${site}/my-orders

_Need help? Contact us:_
📞 03-4297 7668`;
  }

  return { json: { phone, message: msg, order_no: order.order_no, tier: h < 24 ? 'gentle' : h >= 48 ? 'urgent' : 'nudge' } };
}).filter(Boolean);

// Rate-limit: wait 2s between WhatsApp messages
await new Promise(r => setTimeout(r, 2000));
return $input.all();

// Log successful send
return {
  json: {
    success: true,
    sent_to: $('Send WhatsApp Message').first().json?.contacts?.[0]?.wa_id || 'unknown',
    timestamp: new Date().toISOString()
  }
};

// Reminder batch summary
const items = $input.all();
return { json: { total_reminders_sent: items.length, timestamp: new Date().toISOString() } };

// Send cancellation WhatsApp to each auto-cancelled order
const cancelled = $input.first().json;
const site = $('Config (Cron)').first().json.WEBSITE_URL;

if (!Array.isArray(cancelled) || cancelled.length === 0) return [];

return cancelled.map(order => {
  let phone = (order.customer_phone || '').replace(/^\+/, '');
  if (phone.startsWith('0')) phone = '60' + phone.substring(1);
  if (!phone.startsWith('6')) phone = '60' + phone;

  const msg = `⚠️ *Order Auto-Cancelled*\n\nHi ${order.customer_name},\n\nYour order *${order.cancelled_order_no}* has been automatically cancelled because payment was not received within 72 hours.\n\n💰 *Amount:* RM ${parseFloat(order.total).toFixed(2)}\n\nIf this was a mistake, you can place a new order anytime:\n🛒 ${site}\n\n_Questions? Contact us:_\n📞 03-4297 7668\n💬 wa.me/60342977668`;

  return { json: { phone, message: msg } };
}).filter(item => item.json.phone && item.json.phone.length >= 10);
